package com.example.mfa.security;

import com.example.mfa.model.UserAccount;
import com.example.mfa.service.BackupCodeService;
import com.example.mfa.service.UserService;
import org.springframework.security.authentication.AuthenticationProvider;
import org.springframework.security.authentication.BadCredentialsException;
import org.springframework.security.core.Authentication;
import org.springframework.security.core.AuthenticationException;

import java.util.Map;

public class BackupCodeAuthProvider implements AuthenticationProvider {

    private final UserService userService;
    private final BackupCodeService backupCodeService;

    public BackupCodeAuthProvider(UserService userService, BackupCodeService backupCodeService) {
        this.userService = userService;
        this.backupCodeService = backupCodeService;
    }

    @Override
    public Authentication authenticate(Authentication authentication) throws AuthenticationException {
        String username = authentication.getPrincipal() == null ? "" : authentication.getPrincipal().toString();
        String code = authentication.getCredentials() == null ? "" : authentication.getCredentials().toString();

        UserAccount user = userService.loadByUsername(username);
        if (!user.isMfaEnabled()) {
            throw new BadCredentialsException("MFA is not enabled for this account");
        }

        boolean consumed = backupCodeService.consumeBackupCode(user.getId(), code);
        if (!consumed) {
            throw new BadCredentialsException("Invalid backup code");
        }

        var authorities = userService.toUserDetails(user).getAuthorities();
        BackupCodeAuthToken token = new BackupCodeAuthToken(user.getUsername(), authorities);
        token.setDetails(Map.of("consumed", true));
        return token;
    }

    @Override
    public boolean supports(Class<?> authentication) {
        return BackupCodeAuthToken.class.isAssignableFrom(authentication);
    }
}

