package com.example.mfa.service;

import com.example.mfa.model.UserAccount;
import com.example.mfa.repo.UserAccountRepository;
import org.springframework.security.core.authority.SimpleGrantedAuthority;
import org.springframework.security.core.userdetails.User;
import org.springframework.security.crypto.password.PasswordEncoder;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

@Service
public class UserService {

    private final UserAccountRepository userRepo;
    private final PasswordEncoder passwordEncoder;

    public UserService(UserAccountRepository userRepo, PasswordEncoder passwordEncoder) {
        this.userRepo = userRepo;
        this.passwordEncoder = passwordEncoder;
    }

    @Transactional
    public UserAccount createUser(String username, String rawPassword) {
        if (userRepo.existsByUsername(username)) {
            throw new IllegalArgumentException("Username already exists");
        }
        UserAccount u = new UserAccount();
        u.setUsername(username);
        u.setPasswordHash(passwordEncoder.encode(rawPassword));
        u.setMfaEnabled(false);
        return userRepo.save(u);
    }

    @Transactional(readOnly = true)
    public UserAccount loadByUsername(String username) {
        return userRepo.findByUsername(username).orElseThrow(() -> new IllegalArgumentException("User not found"));
    }

    @Transactional(readOnly = true)
    public UserAccount loadById(Long id) {
        return userRepo.findById(id).orElseThrow(() -> new IllegalArgumentException("User not found"));
    }

    @Transactional
    public UserAccount setMfaEnabled(Long userId, boolean enabled) {
        UserAccount u = loadById(userId);
        u.setMfaEnabled(enabled);
        return userRepo.save(u);
    }

    public org.springframework.security.core.userdetails.UserDetails toUserDetails(UserAccount user) {
        return User.withUsername(user.getUsername())
                .password(user.getPasswordHash())
                .authorities(new SimpleGrantedAuthority("ROLE_USER"))
                .accountLocked(false)
                .disabled(false)
                .build();
    }
}

package com.example.mfa.service;

import com.example.mfa.model.MfaBackupCode;
import com.example.mfa.repo.MfaBackupCodeRepository;
import org.springframework.security.crypto.bcrypt.BCryptPasswordEncoder;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

import java.security.SecureRandom;
import java.time.Instant;
import java.util.ArrayList;
import java.util.Base64;
import java.util.List;

@Service
public class BackupCodeService {

    private final MfaBackupCodeRepository repo;
    private final SecureRandom secureRandom = new SecureRandom();
    private final BCryptPasswordEncoder codeHasher = new BCryptPasswordEncoder(12);

    public BackupCodeService(MfaBackupCodeRepository repo) {
        this.repo = repo;
    }

    public record GeneratedBackupCodes(List<String> plainCodes, int count) {}

    @Transactional
    public GeneratedBackupCodes generateAndStore(Long userId, int count) {
        if (count <= 0 || count > 50) throw new IllegalArgumentException("Invalid count");
        repo.deleteByUserId(userId);

        List<String> plain = new ArrayList<>(count);
        for (int i = 0; i < count; i++) {
            String code = generateHumanCode();
            plain.add(code);

            MfaBackupCode entity = new MfaBackupCode();
            entity.setUserId(userId);
            entity.setCodeHash(codeHasher.encode(code));
            entity.setUsed(false);
            repo.save(entity);
        }
        return new GeneratedBackupCodes(List.copyOf(plain), count);
    }

    @Transactional
    public boolean consumeBackupCode(Long userId, String presentedCode) {
        if (presentedCode == null) return false;
        String normalized = normalize(presentedCode);
        if (normalized.isBlank()) return false;

        List<MfaBackupCode> unused = repo.findUnusedForUpdate(userId);
        for (MfaBackupCode c : unused) {
            if (codeHasher.matches(normalized, c.getCodeHash())) {
                c.setUsed(true);
                c.setUsedAt(Instant.now());
                repo.save(c);
                return true;
            }
        }
        return false;
    }

    @Transactional(readOnly = true)
    public int remainingCount(Long userId) {
        return (int) repo.findByUserId(userId).stream().filter(c -> !c.isUsed()).count();
    }

    private String generateHumanCode() {
        byte[] bytes = new byte[9];
        secureRandom.nextBytes(bytes);
        String b64 = Base64.getUrlEncoder().withoutPadding().encodeToString(bytes);
        String normalized = b64.replaceAll("[^A-Za-z0-9]", "").toUpperCase();
        if (normalized.length() < 10) {
            normalized = (normalized + "0000000000").substring(0, 10);
        } else if (normalized.length() > 10) {
            normalized = normalized.substring(0, 10);
        }
        return normalized.substring(0, 5) + "-" + normalized.substring(5);
    }

    private String normalize(String code) {
        return code.trim().replace("-", "").replace(" ", "").toUpperCase();
    }
}

package com.example.mfa.web;

import com.example.mfa.model.UserAccount;
import com.example.mfa.service.BackupCodeService;
import com.example.mfa.service.UserService;
import org.springframework.http.ResponseEntity;
import org.springframework.security.core.Authentication;
import org.springframework.web.bind.annotation.*;

import java.util.List;
import java.util.Map;

@RestController
@RequestMapping("/api")
public class MfaController {

    private final UserService userService;
    private final BackupCodeService backupCodeService;

    public MfaController(UserService userService, BackupCodeService backupCodeService) {
        this.userService = userService;
        this.backupCodeService = backupCodeService;
    }

    public record CreateUserRequest(String username, String password) {}
    public record EnableMfaRequest(boolean enable, Integer backupCodeCount) {}

    @PostMapping("/users")
    public ResponseEntity<?> createUser(@RequestBody CreateUserRequest req) {
        UserAccount u = userService.createUser(req.username(), req.password());
        return ResponseEntity.ok(Map.of(
                "id", u.getId(),
                "username", u.getUsername(),
                "mfaEnabled", u.isMfaEnabled()
        ));
    }

    @PostMapping("/mfa/enable")
    public ResponseEntity<?> enableMfa(Authentication authentication, @RequestBody EnableMfaRequest req) {
        String username = authentication.getName();
        UserAccount u = userService.loadByUsername(username);

        if (!req.enable()) {
            userService.setMfaEnabled(u.getId(), false);
            return ResponseEntity.ok(Map.of("mfaEnabled", false));
        }

        int count = req.backupCodeCount() == null ? 10 : req.backupCodeCount();
        userService.setMfaEnabled(u.getId(), true);
        BackupCodeService.GeneratedBackupCodes codes = backupCodeService.generateAndStore(u.getId(), count);

        return ResponseEntity.ok(Map.of(
                "mfaEnabled", true,
                "backupCodes", codes.plainCodes(),
                "count", codes.count()
        ));
    }

    @GetMapping("/mfa/backup-codes/remaining")
    public ResponseEntity<?> remaining(Authentication authentication) {
        UserAccount u = userService.loadByUsername(authentication.getName());
        return ResponseEntity.ok(Map.of(
                "remaining", backupCodeService.remainingCount(u.getId())
        ));
    }

    @PostMapping("/mfa/backup-codes/regenerate")
    public ResponseEntity<?> regenerate(Authentication authentication, @RequestBody Map<String, Object> body) {
        UserAccount u = userService.loadByUsername(authentication.getName());
        if (!u.isMfaEnabled()) {
            return ResponseEntity.badRequest().body(Map.of("error", "MFA_NOT_ENABLED"));
        }
        int count = body.get("count") == null ? 10 : Integer.parseInt(body.get("count").toString());
        BackupCodeService.GeneratedBackupCodes codes = backupCodeService.generateAndStore(u.getId(), count);
        return ResponseEntity.ok(Map.of(
                "backupCodes", codes.plainCodes(),
                "count", codes.count()
        ));
    }
}

